        function handleInput(key, pressed) {
            if (key === 'KeyP' && pressed) {
                if (gameState === GameState.PLAYING) {
                    gameState = GameState.PAUSED;
                    document.getElementById('pauseMenu').classList.remove('hidden');
                } else if (gameState === GameState.PAUSED) {
                    resumeGame();
                }
            }

            if (key === 'Space' && pressed && gameState === GameState.PLAYING) {
                shoot();
            }
        }

        // 射击
        function shoot() {
            if (shootCooldown <= 0) {
                bullets.push({
                    x: player.x + player.width / 2 - 3,
                    y: player.y,
                    width: 6,
                    height: 15,
                    color: '#ff6b6b'
                });
                shootCooldown = SHOOT_COOLDOWN_TIME;
            }
        }

        // 生成敌人
        function spawnEnemy() {
            if (Math.random() < ENEMY_SPAWN_RATE) {
                const enemyWidth = 30 + Math.random() * 20;
                const enemyHeight = 30 + Math.random() * 20;
                enemies.push({
                    x: Math.random() * (CANVAS_WIDTH - enemyWidth),
                    y: -enemyHeight,
                    width: enemyWidth,
                    height: enemyHeight,
                    color: '#ff9f43',
                    speed: ENEMY_SPEED + Math.random() * 100
