                    width: 6,
                    height: 15,
                    color: '#ff6b6b'
                });
                shootCooldown = SHOOT_COOLDOWN_TIME;
            }
        }

        // 生成敌人
        function spawnEnemy() {
            if (Math.random() < ENEMY_SPAWN_RATE) {
                const enemyWidth = 30 + Math.random() * 20;
                const enemyHeight = 30 + Math.random() * 20;
                enemies.push({
                    x: Math.random() * (CANVAS_WIDTH - enemyWidth),
                    y: -enemyHeight,
                    width: enemyWidth,
                    height: enemyHeight,
                    color: '#ff9f43',
                    speed: ENEMY_SPEED + Math.random() * 100
                });
            }
        }

        // 游戏循环
        function gameLoop(currentTime) {
            const deltaTime = (currentTime - lastTime) / 1000;
            lastTime = currentTime;

            if (gameState === GameState.PLAYING) {
                update(deltaTime);
            }

            render();
            requestAnimationFrame(gameLoop);
        }

        // 更新游戏逻辑
        function update(deltaTime) {
            // 更新射击冷却
            if (shootCooldown > 0) {
                shootCooldown -= deltaTime;
            }

            // 更新玩家位置
            if (keys['ArrowLeft'] || keys['KeyA']) {
                player.x -= PLAYER_SPEED * deltaTime;
            }
            if (keys['ArrowRight'] || keys['KeyD']) {
                player.x += PLAYER_SPEED * deltaTime;
            }

            // 限制玩家在屏幕内
            player.x = Math.max(0, Math.min(CANVAS_WIDTH - player.width, player.x));

            // 更新子弹
            for (let i = bullets.length - 1; i >= 0; i--) {
                bullets[i].y -= BULLET_SPEED * deltaTime;
                if (bullets[i].y + bullets[i].height < 0) {
                    bullets.splice(i, 1);
                }
            }

            // 生成敌人
            spawnEnemy();

            // 更新敌人
            for (let i = enemies.length - 1; i >= 0; i--) {
                enemies[i].y += enemies[i].speed * deltaTime;

                // 敌人到达底部
                if (enemies[i].y > CANVAS_HEIGHT) {
                    enemies.splice(i, 1);
                    continue;
                }

                // 检测子弹与敌人碰撞
                for (let j = bullets.length - 1; j >= 0; j--) {
                    if (checkCollision(bullets[j], enemies[i])) {
                        // 击中敌人
                        score += 10;
                        document.getElementById('scoreValue').textContent = score;
                        enemies.splice(i, 1);
                        bullets.splice(j, 1);
                        break;
                    }
                }

                // 检测玩家与敌人碰撞
                if (enemies[i] && checkCollision(player, enemies[i])) {
                    gameOver();
                    return;
                }
            }
        }

        // 检测碰撞
        function checkCollision(rect1, rect2) {
            return rect1.x < rect2.x + rect2.width &&
                   rect1.x + rect1.width > rect2.x &&
                   rect1.y < rect2.y + rect2.height &&
                   rect1.y + rect1.height > rect2.y;
        }

        // 游戏结束
        function gameOver() {
            gameState = GameState.GAMEOVER;

            // 更新最高分
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('spaceShooterHighScore', highScore);
                document.getElementById('highScoreValue').textContent = highScore;
            }

            document.getElementById('finalScore').textContent = score;
            document.getElementById('gameOverMenu').classList.remove('hidden');
        }

        // 渲染游戏
        function render() {
            // 清空画布
            ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

            // 绘制背景
            const gradient = ctx.createLinearGradient(0, 0, 0, CANVAS_HEIGHT);
            gradient.addColorStop(0, '#1a1a2e');
            gradient.addColorStop(1, '#16213e');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

            // 绘制星星背景
            drawStars();

            if (gameState === GameState.PLAYING || gameState === GameState.PAUSED) {
                // 绘制玩家
                drawPlayer();

                // 绘制子弹
                drawBullets();

                // 绘制敌人
                drawEnemies();
            }
        }

        // 绘制星星背景
        function drawStars() {
            ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            for (let i = 0; i < 50; i++) {
                const x = (Math.sin(i * 0.5 + lastTime * 0.001) * 0.5 + 0.5) * CANVAS_WIDTH;
                const y = (i * 13) % CANVAS_HEIGHT;
                const size = (i % 3) + 1;
                ctx.beginPath();
                ctx.arc(x, y, size, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        // 绘制玩家
        function drawPlayer() {
            ctx.fillStyle = player.color;
            ctx.beginPath();
            ctx.moveTo(player.x + player.width / 2, player.y);
            ctx.lineTo(player.x + player.width, player.y + player.height);
            ctx.lineTo(player.x, player.y + player.height);
            ctx.closePath();
            ctx.fill();

            // 绘制引擎效果
            ctx.fillStyle = '#ff6b6b';
            ctx.beginPath();
            ctx.moveTo(player.x + player.width / 2 - 5, player.y + player.height);
            ctx.lineTo(player.x + player.width / 2 + 5, player.y + player.height);
            ctx.lineTo(player.x + player.width / 2, player.y + player.height + 10);
            ctx.closePath();
            ctx.fill();
        }

        // 绘制子弹
        function drawBullets() {
            bullets.forEach(bullet => {
                ctx.fillStyle = bullet.color;
                ctx.fillRect(bullet.x, bullet.y, bullet.width, bullet.height);
            });
        }

        // 绘制敌人
        function drawEnemies() {
            enemies.forEach(enemy => {
                ctx.fillStyle = enemy.color;
                ctx.beginPath();
                ctx.arc(enemy.x + enemy.width / 2, enemy.y + enemy.height / 2, enemy.width / 2, 0, Math.PI * 2);
                ctx.fill();

                // 绘制敌人细节
                ctx.fillStyle = '#ee5a24';
                ctx.beginPath();
                ctx.arc(enemy.x + enemy.width / 2, enemy.y + enemy.height / 2, enemy.width / 4, 0, Math.PI * 2);
                ctx.fill();
            });
        }

        // 启动游戏
        window.onload = init;
    </script>
</body>
